-- VKD eksik sayfa icerikleri: gazilerimiz, isimsiz-kahramanlar, kadin-kahramanlarimiz, bakanlik
DO $$
DECLARE
  pages jsonb;
  upd record;
  idx int;
  updates jsonb := $vkd_page_updates_json$[{"slug":"gazilerimiz","bodyHtml":"<link rel=\"stylesheet\" href=\"https://fonts.googleapis.com/css2?family=Nunito+Sans:wght@400;600;700;800&family=Merriweather:ital,wght@0,400;0,700;1,400&display=swap\">\n<style>\r\n/* KURUMSAL DEĞİŞKENLER */\r\n.vkv-gazi-wrapper {\r\n  --vkv-r: #8C1A2E; --vkv-rd: #6E1222; --vkv-rl: rgba(140,26,46,.08);\r\n  --vkv-g: #C9A84C; --vkv-gl: rgba(201,168,76,.15);\r\n  --vkv-dk: #0D1117; --vkv-dk2: #1C2330;\r\n  --vkv-t1: #1A1F28; --vkv-t2: #4A5568; --vkv-t3: #718096;\r\n  --vkv-bd: #E4E0D8; --vkv-wh: #FAFAF8;\r\n  font-family: 'Nunito Sans', sans-serif;\r\n  color: var(--vkv-t1);\r\n  line-height: 1.7;\r\n  overflow-x: hidden;\r\n}\r\n\r\n/* HERO ALANI - BAYRAK VE ASKER TEMALI */\r\n.vkv-g-hero {\r\n  background: linear-gradient(rgba(13, 17, 23, 0.85), rgba(28, 35, 48, 0.9)), \r\n              url('https://images.unsplash.com/photo-1571127085130-9774a383802e?q=80&w=2000');\r\n  background-size: cover;\r\n  background-position: center;\r\n  padding: 100px 20px;\r\n  color: #fff;\r\n  text-align: center;\r\n  position: relative;\r\n}\r\n\r\n.vkv-g-hero-content { max-width: 900px; margin: 0 auto; position: relative; z-index: 5; }\r\n.vkv-medal-icon { font-size: 50px; color: var(--vkv-g); margin-bottom: 20px; filter: drop-shadow(0 0 10px rgba(201,168,76,0.5)); }\r\n.vkv-g-hero h1 { font-family: 'Merriweather', serif; font-size: clamp(2.2rem, 5vw, 3.5rem); margin-bottom: 15px; }\r\n.vkv-g-hero h1 em { color: var(--vkv-g); font-style: italic; border-bottom: 3px solid var(--vkv-r); }\r\n.vkv-g-hero p { font-size: 1.1rem; color: rgba(255,255,255,0.7); max-width: 700px; margin: 0 auto; }\r\n\r\n/* TANIM KARTLARI */\r\n.vkv-g-container { max-width: 1100px; margin: 0 auto; padding: 0 20px; }\r\n.vkv-g-grid-2 { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 30px; margin-top: -60px; position: relative; z-index: 10; }\r\n.vkv-g-card { background: #fff; padding: 40px 30px; border-radius: 15px; border-bottom: 6px solid var(--vkv-r); box-shadow: 0 20px 40px rgba(0,0,0,0.1); transition: 0.3s; }\r\n.vkv-g-card:hover { transform: translateY(-10px); }\r\n.vkv-g-card h3 { font-family: 'Merriweather', serif; color: var(--vkv-r); margin-bottom: 15px; font-size: 22px; }\r\n.vkv-g-card.gold { border-bottom-color: var(--vkv-g); }\r\n.vkv-g-card.gold h3 { color: var(--vkv-g); }\r\n\r\n/* ERDEMLER BÖLÜMÜ */\r\n.vkv-g-values { background: var(--vkv-dk); color: #fff; padding: 80px 20px; margin-top: 60px; text-align: center; }\r\n.vkv-val-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 20px; margin-top: 40px; }\r\n.vkv-val-item { background: rgba(255,255,255,0.05); padding: 30px; border-radius: 10px; border-top: 2px solid var(--vkv-g); transition: 0.3s; }\r\n.vkv-val-item:hover { background: rgba(255,255,255,0.1); }\r\n.vkv-val-icon { font-size: 35px; color: var(--vkv-g); margin-bottom: 15px; display: block; }\r\n.vkv-val-item strong { display: block; margin-bottom: 10px; color: #fff; font-size: 18px; }\r\n\r\n/* TARİHÇE */\r\n.vkv-g-history { padding: 80px 20px; background: #fff; }\r\n.vkv-hist-flex { display: flex; align-items: center; gap: 50px; flex-wrap: wrap; }\r\n.vkv-hist-img { flex: 1; min-width: 300px; position: relative; }\r\n.vkv-hist-img img { width: 100%; border-radius: 15px; box-shadow: 15px 15px 0 var(--vkv-r); }\r\n.vkv-hist-text { flex: 1.5; min-width: 300px; }\r\n\r\n/* CTA BANDI */\r\n.vkv-g-cta { background: var(--vkv-r); color: #fff; padding: 50px 20px; text-align: center; margin-top: 50px; }\r\n.vkv-g-btn { display: inline-block; background: var(--vkv-g); color: #000; padding: 15px 40px; border-radius: 5px; font-weight: 800; text-decoration: none; font-size: 16px; margin-top: 20px; transition: 0.3s; }\r\n.vkv-g-btn:hover { background: #fff; color: var(--vkv-r); }\r\n\r\n@media (max-width: 768px) {\r\n  .vkv-g-hero { padding: 60px 20px; }\r\n  .vkv-g-grid-2 { margin-top: 20px; }\r\n}\r\n</style>\r\n\r\n<div class=\"vkv-gazi-wrapper\">\r\n  <section class=\"vkv-g-hero\">\r\n    <div class=\"vkv-g-hero-content\">\r\n      <div class=\"vkv-medal-icon\">🎖️</div>\r\n      <div style=\"color: var(--vkv-g); font-weight: 800; letter-spacing: 4px; margin-bottom: 10px; text-transform: uppercase; font-size: 13px;\">🇹🇷 VATAN KAHRAMANLARI VAKFI</div>\r\n      <h1>Kahramanlığın Yaşayan Abidesi: <em>GAZİ</em></h1>\r\n      <p>Gazilik; bir rütbe değil, Türk milletinin evladına takabileceği en kutsal şeref madalyasıdır.</p>\r\n    </div>\r\n  </section>\r\n\r\n  <div class=\"vkv-g-container\">\r\n    <div class=\"vkv-g-grid-2\">\r\n      <div class=\"vkv-g-card\">\r\n        <h3>⚔️ Muharip Gazi</h3>\r\n        <p>Türk Silahlı Kuvvetleri mensuplarından harbe fiilen katılanları ifade eder. Cephe hattında vatan savunmasına bizzat iştirak eden kahramanlarımızdır.</p>\r\n      </div>\r\n      <div class=\"vkv-g-card gold\">\r\n        <h3>🛡️ Malul Gazi</h3>\r\n        <p>Vatanın bölünmez bütünlüğü için terör örgütlerine karşı mücadelede yaralanarak sakatlığı raporla kesinleşen yiğitlerimizdir.</p>\r\n      </div>\r\n    </div>\r\n\r\n    <div style=\"margin-top: 80px; text-align: center;\">\r\n      <h2 style=\"font-family: 'Merriweather', serif; font-size: 32px; margin-bottom: 20px;\">Gazilik Şanı ve Erdemleri</h2>\r\n      <p style=\"max-width: 800px; margin: 0 auto; color: var(--vkv-t2);\">Cumhuriyetimizin en büyük Gazisi, Mustafa Kemal ATATÜRK'ün yaşayan canlı temsilcisi olan gazilerimiz, yüksek şeref ve fazilet sahibidir.</p>\r\n    </div>\r\n  </div>\r\n\r\n  <section class=\"vkv-g-values\">\r\n    <div class=\"vkv-g-container\">\r\n      <div class=\"vkv-val-grid\">\r\n        <div class=\"vkv-val-item\">\r\n          <span class=\"vkv-val-icon\">🏛️</span>\r\n          <strong>Devletin Emrinde</strong>\r\n          <p style=\"font-size: 13px; opacity: 0.7;\">Canını vatanı için feda etmeye hazır olan gazi, her zaman devletinin ve bayrağının yanındadır.</p>\r\n        </div>\r\n        <div class=\"vkv-val-item\">\r\n          <span class=\"vkv-val-icon\">🤝</span>\r\n          <strong>Silah Arkadaşlığı</strong>\r\n          <p style=\"font-size: 13px; opacity: 0.7;\">Bütün gazi arkadaşlarını candan sever, onlara karşı hoşgörülü ve birleştiricidir.</p>\r\n        </div>\r\n        <div class=\"vkv-val-item\">\r\n          <span class=\"vkv-val-icon\">💎</span>\r\n          <strong>Vakarlı Duruş</strong>\r\n          <p style=\"font-size: 13px; opacity: 0.7;\">Gazilik şanını şahsi menfaat için kullanmaz, kimseden bir şey istemez, kimseye el açmaz.</p>\r\n        </div>\r\n        <div class=\"vkv-val-item\">\r\n          <span class=\"vkv-val-icon\">🦅</span>\r\n          <strong>Cumhuriyet Aşkı</strong>\r\n          <p style=\"font-size: 13px; opacity: 0.7;\">Atatürk sevdası ve ay-yıldızlı bayrak sevgisi kalbinde sönmeyen bir volkan gibidir.</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </section>\r\n\r\n  <section class=\"vkv-g-history\">\r\n    <div class=\"vkv-g-container\">\r\n      <div class=\"vkv-hist-flex\">\r\n        <div class=\"vkv-hist-img\">\r\n          <img src=\"https://images.unsplash.com/photo-1590234900693-80e793910543?q=80&amp;w=1000\" alt=\"Sakarya Meydan Muharebesi\">\r\n          <div style=\"position: absolute; top: -20px; left: -20px; background: var(--vkv-g); color: #000; padding: 15px; font-weight: 900; border-radius: 5px;\">19 EYLÜL 1921</div>\r\n        </div>\r\n        <div class=\"vkv-hist-text\">\r\n          <h2 style=\"font-family: 'Merriweather', serif; font-size: 28px; margin-bottom: 20px;\">Gaziler Günü'nün Doğuşu</h2>\r\n          <p>13 Eylül 1921’de kazanılan Sakarya Zaferi’nin hemen ardından, TBMM tarafından Başkomutan Mustafa Kemal ATATÜRK'e <strong>\"MAREŞAL\"</strong> rütbesi ve <strong>\"GAZİ\"</strong> ünvanı verilmiştir.</p>\r\n          <div style=\"background: var(--vkv-gr); padding: 25px; border-left: 5px solid var(--vkv-g); font-style: italic; margin: 20px 0;\">\r\n            \"Bizzat muharebe meydanındaki tedbiriyle muzafferiyetin amil ve müessiri olmuş Başkumandan Mustafa Kemal Paşa Hazretlerine gazilik ünvanı tevcihini teklif ederiz.\"\r\n          </div>\r\n          <p style=\"font-size: 14px; color: var(--vkv-t3);\">Bu sebeple her yıl 19 Eylül, kahraman gazilerimize şükranlarımızı sunduğumuz resmi \"Gaziler Günü\" olarak kutlanır.</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </section>\r\n\r\n  <section class=\"vkv-g-cta\">\r\n    <div class=\"vkv-g-container\">\r\n      <h2 style=\"font-family: 'Merriweather', serif; font-size: 26px;\">Vefa Borcumuzu Birlikte Ödeyelim</h2>\r\n      <p style=\"opacity: 0.9;\">Gazilerimizin rehabilitasyon süreçlerine destek olmak için vakfımıza katkıda bulunabilirsiniz.</p>\r\n      <a href=\"/bagis\" class=\"vkv-g-btn\">❤️ DESTEK OLUN</a>\r\n    </div>\r\n  </section>\r\n</div>"},{"slug":"isimsiz-kahramanlar","bodyHtml":"<link rel=\"stylesheet\" href=\"https://fonts.googleapis.com/css2?family=Nunito+Sans:wght@400;600;700;800&family=Merriweather:ital,wght@0,400;0,700;1,400&display=swap\">\n<style>\r\n/* İSİMSİZ KAHRAMANLAR - ÖZEL TASARIM */\r\n.vkv-secret-wrapper {\r\n  --vkv-r: #8C1A2E; \r\n  --vkv-g: #C9A84C; \r\n  --vkv-dk: #0D1117;\r\n  --vkv-dk2: #161B22;\r\n  --vkv-t1: #F0F6FC;\r\n  --vkv-t2: #8B949E;\r\n  --vkv-bg: #0D1117;\r\n  font-family: 'Nunito Sans', sans-serif;\r\n  background: var(--vkv-bg);\r\n  color: var(--vkv-t1);\r\n  line-height: 1.6;\r\n}\r\n\r\n/* Teşkilat Hero Alanı */\r\n.secret-hero {\r\n  background: linear-gradient(rgba(13, 17, 23, 0.9), rgba(13, 17, 23, 0.95)), \r\n              url('https://images.unsplash.com/photo-1455390582262-044cdead277a?q=80&w=2000'); /* Eski evrak/kalem teması */\r\n  background-size: cover;\r\n  background-position: center;\r\n  padding: 140px 20px;\r\n  text-align: center;\r\n  border-bottom: 3px solid var(--vkv-r);\r\n}\r\n\r\n.secret-hero h1 { font-family: 'Merriweather', serif; font-size: clamp(2rem, 5vw, 3.5rem); margin-bottom: 20px; letter-spacing: 2px; }\r\n.secret-hero h1 em { color: var(--vkv-g); font-style: normal; text-transform: uppercase; }\r\n.secret-hero p { max-width: 800px; margin: 0 auto; opacity: 0.8; font-size: 1.1rem; font-style: italic; }\r\n\r\n/* Şifreli Mesaj Bandı */\r\n.cipher-band {\r\n  background: var(--vkv-r);\r\n  padding: 15px 0;\r\n  text-align: center;\r\n  font-family: monospace;\r\n  font-size: 12px;\r\n  letter-spacing: 5px;\r\n  color: #fff;\r\n  opacity: 0.7;\r\n}\r\n\r\n/* Teşkilat Kartları */\r\n.secret-container { max-width: 1200px; margin: 0 auto; padding: 80px 20px; }\r\n\r\n.secret-grid {\r\n  display: grid;\r\n  grid-template-columns: repeat(auto-fit, minmax(350px, 1fr));\r\n  gap: 30px;\r\n}\r\n\r\n.secret-card {\r\n  background: var(--vkv-dk2);\r\n  border: 1px solid #30363d;\r\n  border-radius: 8px;\r\n  padding: 40px;\r\n  position: relative;\r\n  transition: 0.3s;\r\n  overflow: hidden;\r\n}\r\n\r\n.secret-card::before {\r\n  content: 'TOP SECRET';\r\n  position: absolute;\r\n  top: 10px;\r\n  right: -30px;\r\n  background: #21262d;\r\n  color: #8b949e;\r\n  font-size: 10px;\r\n  padding: 5px 40px;\r\n  transform: rotate(45deg);\r\n  font-weight: 800;\r\n}\r\n\r\n.secret-card:hover {\r\n  border-color: var(--vkv-g);\r\n  transform: translateY(-5px);\r\n  box-shadow: 0 10px 30px rgba(0,0,0,0.5);\r\n}\r\n\r\n.secret-icon { font-size: 40px; color: var(--vkv-g); margin-bottom: 20px; display: block; }\r\n.secret-name { font-family: 'Merriweather', serif; font-size: 22px; color: var(--vkv-g); margin-bottom: 15px; border-bottom: 1px solid #30363d; padding-bottom: 10px; }\r\n.secret-desc { font-size: 14px; color: var(--vkv-t2); margin-bottom: 20px; text-align: justify; }\r\n\r\n.secret-tags { display: flex; gap: 10px; flex-wrap: wrap; }\r\n.s-tag { font-size: 10px; background: rgba(140, 26, 46, 0.2); color: #ff7b72; padding: 4px 10px; border-radius: 4px; font-weight: 700; text-transform: uppercase; }\r\n\r\n/* Lobi ve Diplomasi */\r\n.lobi-sec { background: #f0f6fc; color: #1c2128; padding: 80px 20px; }\r\n.lobi-w { max-width: 900px; margin: 0 auto; text-align: center; }\r\n.lobi-w h2 { font-family: 'Merriweather', serif; font-size: 2.5rem; margin-bottom: 20px; color: var(--vkv-r); }\r\n.lobi-card { background: #fff; padding: 40px; border-radius: 15px; box-shadow: 0 10px 30px rgba(0,0,0,0.05); margin-top: 40px; border-left: 5px solid var(--vkv-g); text-align: left; }\r\n\r\n/* Footer Message */\r\n.secret-footer { padding: 60px 20px; text-align: center; background: var(--vkv-dk); }\r\n\r\n@media (max-width: 768px) {\r\n  .secret-grid { grid-template-columns: 1fr; }\r\n}\r\n</style>\r\n\r\n<div class=\"vkv-secret-wrapper\">\r\n  <section class=\"secret-hero\">\r\n    <div style=\"font-size: 50px; margin-bottom: 20px;\">👤</div>\r\n    <h1>Gölgedeki Vatan: <em>İsimsiz Kahramanlar</em></h1>\r\n    <p>Onların isimleri mezar taşlarında yazmaz, fotoğrafları gazetelerde çıkmaz. Onlar vatanın görünmez muhafızları, sessiz çığlıkları ve lobi sahalarındaki çelik iradesidir.</p>\r\n  </section>\r\n\r\n  <div class=\"cipher-band\">\r\n    01010110 01000001 01010100 01000001 01001110 -- SAGOLSUN -- 01010100 01000101 01010011 01001011 01001001 01001100 01000001 01010100\r\n  </div>\r\n\r\n  <div class=\"secret-container\">\r\n    <div class=\"secret-grid\">\r\n\r\n      <div class=\"secret-card\">\r\n        <span class=\"secret-icon\">🦅</span>\r\n        <h3 class=\"secret-name\">Teşkilat-ı Mahsusa</h3>\r\n        <p class=\"secret-desc\">Osmanlı'nın son döneminden Milli Mücadele'ye köprü kuran ilk milli istihbarat servisimiz. Kuşçubaşı Eşref'ten Yakup Cemil'e kadar, üç kıtada operasyon yürüten, Trablusgarp'tan Orta Asya'ya vatan savunmasını örgütleyen efsanevi yapı.</p>\r\n        <div class=\"secret-tags\">\r\n          <span class=\"s-tag\">Derin Operasyon</span>\r\n          <span class=\"s-tag\">Hücre Yapılanması</span>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"secret-card\">\r\n        <span class=\"secret-icon\">🔑</span>\r\n        <h3 class=\"secret-name\">Karakol Cemiyeti</h3>\r\n        <p class=\"secret-desc\">İstanbul işgal altındayken, Anadolu'ya silah, mühimmat ve komutan kaçıran gizli yer altı teşkilatı. \"Yavuz\" grubuyla Anadolu'daki direnişi lojistik olarak besleyen, düşmanın planlarını anlık olarak Ankara'ya raporlayan isimsizlerin adresi.</p>\r\n        <div class=\"secret-tags\">\r\n          <span class=\"s-tag\">Lojistik</span>\r\n          <span class=\"s-tag\">İstihbarat</span>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"secret-card\">\r\n        <span class=\"secret-icon\">🛡️</span>\r\n        <h3 class=\"secret-name\">Müsellah Müdafaa-i Milliye</h3>\r\n        <p class=\"secret-desc\">Kısa adıyla \"Mim Mim\". TBMM tarafından resmen tanınan gizli istihbarat grubu. İşgal kuvvetlerinin içine sızarak en kritik belgeleri ele geçiren, vatan hainlerini etkisiz hale getiren ve Milli Mücadele'nin görünmez kalkanı olan teşkilat.</p>\r\n        <div class=\"secret-tags\">\r\n          <span class=\"s-tag\">Sızma</span>\r\n          <span class=\"s-tag\">Karşı İstihbarat</span>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"secret-card\">\r\n        <span class=\"secret-icon\">📜</span>\r\n        <h3 class=\"secret-name\">Felah Grubu</h3>\r\n        <p class=\"secret-desc\">Milli Mücadele'nin son döneminde İstanbul'da kurulan, bilgi toplama ve kamuoyu oluşturma konusunda uzmanlaşmış birim. Özellikle lobi faaliyetleri ve diplomasi trafiğinde gizli kanallar açarak Türk tezlerini dünyaya duyurmuştur.</p>\r\n        <div class=\"secret-tags\">\r\n          <span class=\"s-tag\">Diplomasi</span>\r\n          <span class=\"s-tag\">Bilgi Akışı</span>\r\n        </div>\r\n      </div>\r\n\r\n    </div>\r\n  </div>\r\n\r\n  <section class=\"lobi-sec\">\r\n    <div class=\"lobi-w\">\r\n      <h2>Savaş Sadece Cephede Değildir</h2>\r\n      <p style=\"font-size: 1.1rem; color: #484f58;\">Uluslararası arenada Türk davasını savunan, diaspora ağlarını yöneten ve yabancı başkentlerde Türk bayrağının onurunu koruyan lobi kahramanlarımız, zaferin siyasi ve diplomatik mimarlarıdır.</p>\r\n      \r\n      <div class=\"lobi-card\">\r\n        <h4 style=\"font-family: 'Merriweather', serif; font-size: 20px; color: var(--vkv-r); margin-bottom: 15px;\">Lobi Kahramanlarımızın Misyonu</h4>\r\n        <ul style=\"list-style: none; padding: 0; margin: 0; font-size: 15px; line-height: 2;\">\r\n          <li>📌 Yabancı parlamentolarda Türk haklarının savunulması.</li>\r\n          <li>📌 Sözde iddialara karşı tarihi gerçeklerin bilimsel ve diplomatik temsili.</li>\r\n          <li>📌 Türk diasporasını tek bir çatı altında birleştirerek kolektif bir güç oluşturulması.</li>\r\n          <li>📌 Vakfımızın faaliyet gösterdiği 13 ülkede yerel otoritelerle stratejik iş birlikleri.</li>\r\n        </ul>\r\n      </div>\r\n    </div>\r\n  </section>\r\n\r\n  <section class=\"secret-footer\">\r\n    <div style=\"max-width: 800px; margin: 0 auto;\">\r\n      <h3 style=\"font-family: 'Merriweather', serif; color: var(--vkv-g); margin-bottom: 15px;\">İsimsizler Unutulmaz</h3>\r\n      <p style=\"opacity: 0.7; font-size: 14px;\">\"Bizler isimlerimizi vatan toprağına, mühürlerimizi tarihin derinliklerine kazıdık. Kimse bilmese de vatan sağ olsun.\"</p>\r\n      <a href=\"/bagis\" style=\"display: inline-block; background: var(--vkv-r); color: #fff; padding: 15px 45px; border-radius: 5px; font-weight: 800; text-decoration: none; margin-top: 30px; transition: 0.3s;\">❤️ VEFA BORCUMUZU ÖDEYELİM</a>\r\n    </div>\r\n  </section>\r\n</div>"},{"slug":"kadin-kahramanlarimiz","bodyHtml":"<link rel=\"stylesheet\" href=\"https://fonts.googleapis.com/css2?family=Nunito+Sans:wght@400;600;700;800&family=Merriweather:ital,wght@0,400;0,700;1,400&display=swap\">\n<style>\r\n/* KAHRAMAN KADINLARIMIZ - SABİHA GÖKÇEN EKLEMLİ TAM TASARIM */\r\n.vkv-heroines-wrapper {\r\n  --vkv-r: #8C1A2E; /* Bordo */\r\n  --vkv-g: #C9A84C; /* Altın */\r\n  --vkv-dk: #0D1117;\r\n  --vkv-t1: #1A1F28;\r\n  --vkv-t2: #4A5568;\r\n  --vkv-bg: #FAFAF8;\r\n  font-family: 'Nunito Sans', sans-serif;\r\n  background: var(--vkv-bg);\r\n  color: var(--vkv-t1);\r\n  line-height: 1.6;\r\n}\r\n\r\n/* Saygın Hero Alanı */\r\n.vh-hero {\r\n  background: linear-gradient(rgba(13, 17, 23, 0.9), rgba(13, 17, 23, 0.95)), \r\n              url('https://images.unsplash.com/photo-1571127085130-9774a383802e?q=80&w=2000');\r\n  background-size: cover;\r\n  background-position: center;\r\n  padding: 100px 20px;\r\n  text-align: center;\r\n  color: #fff;\r\n  border-bottom: 5px solid var(--vkv-r);\r\n}\r\n\r\n.vh-hero h1 { font-family: 'Merriweather', serif; font-size: clamp(2rem, 5vw, 3.5rem); margin-bottom: 20px; }\r\n.vh-hero h1 em { color: var(--vkv-g); font-style: italic; }\r\n.vh-hero p { max-width: 800px; margin: 0 auto; opacity: 0.8; font-size: 1.1rem; }\r\n\r\n/* Grid Yapısı */\r\n.vh-container { max-width: 1300px; margin: 0 auto; padding: 60px 20px; }\r\n.vh-grid {\r\n  display: grid;\r\n  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));\r\n  gap: 25px;\r\n}\r\n\r\n/* Kahraman Kartları */\r\n.vh-card {\r\n  background: #fff;\r\n  border-radius: 15px;\r\n  overflow: hidden;\r\n  box-shadow: 0 10px 25px rgba(0,0,0,0.06);\r\n  border: 1px solid #E4E0D8;\r\n  transition: 0.3s;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.vh-card:hover { transform: translateY(-10px); border-color: var(--vkv-r); box-shadow: 0 20px 40px rgba(140, 26, 46, 0.1); }\r\n\r\n.vh-card-header {\r\n  background: var(--vkv-r);\r\n  color: #fff;\r\n  padding: 20px;\r\n  text-align: center;\r\n  position: relative;\r\n}\r\n\r\n.vh-card-header::after {\r\n  content: '';\r\n  position: absolute;\r\n  bottom: -10px;\r\n  left: 50%;\r\n  transform: translateX(-50%);\r\n  border-left: 10px solid transparent;\r\n  border-right: 10px solid transparent;\r\n  border-top: 10px solid var(--vkv-r);\r\n}\r\n\r\n.vh-card-header h3 { font-family: 'Merriweather', serif; font-size: 18px; margin: 0; letter-spacing: 0.5px; }\r\n\r\n.vh-body { padding: 35px 25px 25px; flex-grow: 1; text-align: center; }\r\n.vh-tag { \r\n  display: inline-block; \r\n  background: rgba(201,168,76,0.1); \r\n  color: #7a5a00; \r\n  font-size: 10px; \r\n  font-weight: 800; \r\n  padding: 4px 12px; \r\n  border-radius: 20px; \r\n  margin-bottom: 15px; \r\n  text-transform: uppercase;\r\n}\r\n\r\n.vh-desc { font-size: 14px; color: var(--vkv-t2); line-height: 1.8; }\r\n\r\n/* Alt Bilgi Bandı */\r\n.vh-footer-msg {\r\n  background: var(--vkv-dk);\r\n  color: #fff;\r\n  padding: 60px 20px;\r\n  text-align: center;\r\n  margin-top: 40px;\r\n}\r\n.vh-footer-msg blockquote {\r\n  font-family: 'Merriweather', serif;\r\n  font-size: 1.4rem;\r\n  max-width: 900px;\r\n  margin: 0 auto;\r\n  font-style: italic;\r\n  border: none;\r\n}\r\n\r\n@media (max-width: 768px) {\r\n  .vh-hero { padding: 60px 20px; }\r\n  .vh-grid { grid-template-columns: 1fr; }\r\n}\r\n</style>\r\n\r\n<div class=\"vkv-heroines-wrapper\">\r\n  <section class=\"vh-hero\">\r\n    <div style=\"font-size: 50px; margin-bottom: 20px;\">🎖️</div>\r\n    <h1>İstiklalimizin Meşalesi: <em>Kadın Kahramanlarımız</em></h1>\r\n    <p>Vatan savunmasında canını siper eden, mermiyi kucağında, hürriyeti göklerde taşıyan asil Türk kadınlarının hatırasına...</p>\r\n  </section>\r\n\r\n  <div class=\"vh-container\">\r\n    <div class=\"vh-grid\">\r\n\r\n      <div class=\"vh-card\">\r\n        <div class=\"vh-card-header\" style=\"background: var(--vkv-dk2, #1C2330);\"><h3>Sabiha Gökçen</h3></div>\r\n        <div class=\"vh-body\">\r\n          <span class=\"vh-tag\">Dünyanın İlk Kadın Savaş Pilotu</span>\r\n          <p class=\"vh-desc\">Atatürk'ün manevi kızı olan Sabiha Gökçen, Türk kadınının gökyüzündeki temsilcisidir. 1937 yılındaki askeri harekâtta bizzat görev almış, hayatı boyunca sayısız pilot yetiştirerek Türk havacılığına öncülük etmiştir.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"vh-card\">\r\n        <div class=\"vh-card-header\"><h3>Kara Fatma</h3></div>\r\n        <div class=\"vh-body\">\r\n          <span class=\"vh-tag\">Üsteğmen / Batı Cephesi</span>\r\n          <p class=\"vh-desc\">Fatma Seher Erden, Balkan Savaşı'ndan itibaren mücadeleye katılmış, Kurtuluş Savaşı'nda Üsteğmen rütbesiyle 300 kişilik bir müfrezeyi komuta etmiştir.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"vh-card\">\r\n        <div class=\"vh-card-header\"><h3>Şerife Bacı</h3></div>\r\n        <div class=\"vh-body\">\r\n          <span class=\"vh-tag\">İnebolu-Ankara Hattı</span>\r\n          <p class=\"vh-desc\">Kastamonu'nun ağır kış şartlarında cephane taşırken, mermiler ıslanmasın diye bebeğinin battaniyesini mühimmata saran ve donarak şehadete yürüyen vefa abidesidir.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"vh-card\">\r\n        <div class=\"vh-card-header\"><h3>Nezahat Onbaşı</h3></div>\r\n        <div class=\"vh-body\">\r\n          <span class=\"vh-tag\">70. Alay / Gediz</span>\r\n          <p class=\"vh-desc\">Babasıyla birlikte cephede büyüyen ve henüz 12 yaşında onbaşı rütbesi alan Nezahat Baysel, Kurtuluş Savaşı'nın en genç kahramanlarından biridir.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"vh-card\">\r\n        <div class=\"vh-card-header\"><h3>Halime Çavuş</h3></div>\r\n        <div class=\"vh-body\">\r\n          <span class=\"vh-tag\">Kastamonu / İnebolu</span>\r\n          <p class=\"vh-desc\">Kadın olduğunun anlaşılmaması için traş olan ve uzun süre erkek kılığında orduya hizmet eden Halime Kocabıyık, cepheye mühimmat taşırken gösterdiği cesaretle bilinir.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"vh-card\">\r\n        <div class=\"vh-card-header\"><h3>Gördesli Makbule</h3></div>\r\n        <div class=\"vh-body\">\r\n          <span class=\"vh-tag\">Manisa / Akhisar</span>\r\n          <p class=\"vh-desc\">Henüz 22 yaşında yeni evliyken eşiyle birlikte dağlara çıkan, Yunan kuvvetlerine karşı kahramanca çarpışırken şehit düşen bir vatan sevdalısıdır.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"vh-card\">\r\n        <div class=\"vh-card-header\"><h3>Tayyar Rahmiye</h3></div>\r\n        <div class=\"vh-body\">\r\n          <span class=\"vh-tag\">Osmaniye / Güney Cephesi</span>\r\n          <p class=\"vh-desc\">Fransızlara karşı müfreze komutanlığı yapan, hızı ve atılganlığı nedeniyle \"Tayyar\" lakabıyla anılan, en önde şehadete koşan kahramanımızdır.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"vh-card\">\r\n        <div class=\"vh-card-header\"><h3>Halide Edib Adıvar</h3></div>\r\n        <div class=\"vh-body\">\r\n          <span class=\"vh-tag\">Halide Onbaşı / Aydın</span>\r\n          <p class=\"vh-desc\">İstanbul mitinglerindeki tarihi konuşmaları ve cephedeki hatipliği ile halkı uyandıran, mücadeleye bizzat onbaşı rütbesiyle katılan aydın liderdir.</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"vh-card\">\r\n        <div class=\"vh-card-header\"><h3>Çete Ayşe</h3></div>\r\n        <div class=\"vh-body\">\r\n          <span class=\"vh-tag\">Aydın / Kuvayı Milliye</span>\r\n          <p class=\"vh-desc\">Eşinin intikamını almak için ziynetlerini satıp silah alan, Aydın'da dağa çıkarak Yunan işgaline karşı ilk kurşunlardan birini atan yiğit Efe kadınıdır.</p>\r\n        </div>\r\n      </div>\r\n\r\n    </div>\r\n  </div>\r\n\r\n  <section class=\"vh-footer-msg\">\r\n    <blockquote>\r\n      \"Dünya üzerinde gördüğünüz her şey kadının eseridir.\"<br>\r\n      <small style=\"font-size: 1rem; opacity: 0.6;\">— Gazi Mustafa Kemal Atatürk</small>\r\n    </blockquote>\r\n  </section>\r\n\r\n  <div style=\"background: var(--vkv-r); padding: 40px; text-align: center; color: #fff;\">\r\n    <h3 style=\"font-family: 'Merriweather', serif; margin-bottom: 20px;\">Bu Aziz Hatırayı Birlikte Yaşatalım</h3>\r\n    <a href=\"/bagis\" style=\"display: inline-block; background: var(--vkv-g); color: #000; padding: 15px 40px; border-radius: 5px; font-weight: 800; text-decoration: none;\">❤️ DESTEK OLUN</a>\r\n  </div>\r\n</div>"},{"slug":"bakanlik","bodyHtml":"<style>\r\n:root{\r\n  --primary:#0a1f44;\r\n  --accent:#c9a96e;\r\n  --bg:#f8f9fc;\r\n  --text:#1a1a1a;\r\n}\r\n\r\n.vkd-bakanlik-scope {\r\n  font-family: 'Segoe UI', sans-serif;\r\n  background:var(--bg);\r\n  color:var(--text);\r\n  line-height:1.8;\r\n}\r\n\r\n.report-container{\r\n  max-width:1100px;\r\n  margin:60px auto;\r\n  background:#fff;\r\n  padding:60px;\r\n  border-radius:16px;\r\n  box-shadow:0 10px 40px rgba(0,0,0,0.08);\r\n}\r\n\r\n.report-title{\r\n  font-size:32px;\r\n  font-weight:800;\r\n  color:var(--primary);\r\n  margin-bottom:10px;\r\n}\r\n\r\n.report-subtitle{\r\n  font-size:18px;\r\n  color:#666;\r\n  margin-bottom:40px;\r\n}\r\n\r\n.section{\r\n  margin-bottom:60px;\r\n}\r\n\r\n.section h2{\r\n  font-size:24px;\r\n  color:var(--primary);\r\n  border-left:5px solid var(--accent);\r\n  padding-left:15px;\r\n  margin-bottom:20px;\r\n}\r\n\r\n.section p{\r\n  margin-bottom:18px;\r\n  text-align:justify;\r\n}\r\n\r\n.highlight{\r\n  background:#f3f6ff;\r\n  padding:20px;\r\n  border-left:4px solid var(--accent);\r\n  border-radius:8px;\r\n  margin:20px 0;\r\n}\r\n\r\n.footer{\r\n  text-align:center;\r\n  margin-top:60px;\r\n  font-weight:600;\r\n  color:#777;\r\n}\r\n</style>\r\n\r\n<div class=\"report-container\">\r\n\r\n<div class=\"report-title\">\r\nGAZİ VE ŞEHİT YAKINLARI BAKANLIĞI KURULMASI\r\n</div>\r\n\r\n<div class=\"report-subtitle\">\r\nStratejik Araştırma Dosyası – Vatan Kahramanları Derneği\r\n</div>\r\n\r\n<!-- 1 -->\r\n<div class=\"section\">\r\n<h2>1. Araştırmanın Amacı</h2>\r\n<p>\r\nBu araştırma, Türkiye Cumhuriyeti’nde şehit yakınları ve gazilere yönelik kamu hizmetlerinin mevcut yapısını analiz etmek ve bu hizmetlerin daha etkin, bütüncül ve sürdürülebilir hale getirilmesi için gerekli kurumsal dönüşüm modelini ortaya koymak amacıyla hazırlanmıştır.\r\n</p>\r\n<p>\r\nŞehitlik ve gazilik, klasik sosyal politika alanlarının ötesinde değerlendirilmesi gereken özel statülerdir. Bu nedenle bu alana yönelik hizmetlerin parçalı yapılar yerine tek çatı altında yürütülmesi gerekliliği ortaya çıkmaktadır.\r\n</p>\r\n</div>\r\n\r\n<!-- 2 -->\r\n<div class=\"section\">\r\n<h2>2. Kapsam ve Yöntem</h2>\r\n<p>\r\nAraştırma; hukuki, idari ve sosyal boyutları kapsayan çok disiplinli bir yaklaşımla hazırlanmıştır. Çalışma kapsamında mevcut mevzuat, kamu kurumları ve hizmet süreçleri detaylı şekilde analiz edilmiştir.\r\n</p>\r\n<p>\r\nYöntem olarak mevzuat incelemesi, kurumsal analiz ve karşılaştırmalı model incelemesi kullanılmıştır. Bu sayede teorik ve pratik açıdan uygulanabilir bir model geliştirilmiştir.\r\n</p>\r\n</div>\r\n\r\n<!-- 3 -->\r\n<div class=\"section\">\r\n<h2>3. Kavramsal ve Kuramsal Çerçeve</h2>\r\n<p>\r\nŞehit yakınları ve gazilere yönelik hizmetler, yardım temelli değil hak temelli bir yaklaşımla ele alınmalıdır. Bu yaklaşım, devletin sorumluluğunu açık şekilde tanımlar.\r\n</p>\r\n<div class=\"highlight\">\r\nBu haklar bir ayrıcalık değil, devletin yerine getirmekle yükümlü olduğu bir sorumluluktur.\r\n</div>\r\n<p>\r\nBu çerçevede sosyal devlet, onur temelli yönetim ve hak temelli yaklaşım birlikte değerlendirilmiştir.\r\n</p>\r\n</div>\r\n\r\n<!-- 4 -->\r\n<div class=\"section\">\r\n<h2>4. Mevcut Durum Analizi</h2>\r\n<p>\r\nTürkiye’de şehit yakınları ve gazilere yönelik hizmetler farklı kurumlara dağılmış durumdadır. Bu durum koordinasyon eksikliği ve hizmet gecikmelerine yol açmaktadır.\r\n</p>\r\n<p>\r\nParçalı yapı, vatandaşın birden fazla kuruma başvurmasını zorunlu kılmakta ve kamu hizmetlerinin etkinliğini düşürmektedir.\r\n</p>\r\n</div>\r\n\r\n<!-- 5 -->\r\n<div class=\"section\">\r\n<h2>5. Sorun Alanlarının Tespiti</h2>\r\n<p>\r\nMevcut sistemde bürokratik çok başlılık, hak eşitsizliği ve statü farklılıkları gibi temel sorunlar bulunmaktadır. Özellikle gaziler arasında maaş ve hak farklılıkları ciddi adaletsizliklere yol açmaktadır.\r\n</p>\r\n<p>\r\nBunun yanında psikolojik destek eksikliği ve aidiyet sorunu da önemli yapısal problemler arasındadır.\r\n</p>\r\n</div>\r\n\r\n<!-- 6 -->\r\n<div class=\"section\">\r\n<h2>6. Hukukî İnceleme</h2>\r\n<p>\r\nMevzuatın parçalı yapısı, uygulamada farklılıklara ve hak kayıplarına neden olmaktadır. Bu durum hukuki belirsizlik yaratmakta ve kamu yönetiminde sorunlara yol açmaktadır.\r\n</p>\r\n</div>\r\n\r\n<!-- 7 -->\r\n<div class=\"section\">\r\n<h2>7. Uluslararası Model Analizi</h2>\r\n<p>\r\nUluslararası örnekler incelendiğinde, hizmetlerin tek çatı altında toplandığı modellerin daha başarılı olduğu görülmektedir. Bu modeller, hizmet kalitesini ve erişilebilirliği artırmaktadır.\r\n</p>\r\n</div>\r\n\r\n<!-- 8 -->\r\n<div class=\"section\">\r\n<h2>8. Kurumsal Yapı Önerisi</h2>\r\n<p>\r\nÖnerilen model, merkezi ve uzmanlaşmış bir bakanlık yapısını içermektedir. Bu yapı, hizmetlerin tek noktadan yürütülmesini sağlayacaktır.\r\n</p>\r\n</div>\r\n\r\n<!-- 9 -->\r\n<div class=\"section\">\r\n<h2>9. Politika ve Reform Önerileri</h2>\r\n<p>\r\nTek çatı sistemi, mevzuat reformu ve dijital entegrasyon bu dönüşümün temel unsurlarıdır. Bu reformlar, kamu hizmetlerinde etkinliği artıracaktır.\r\n</p>\r\n</div>\r\n\r\n<!-- 10 -->\r\n<div class=\"section\">\r\n<h2>10. Ekonomik ve İdari Etki Analizi</h2>\r\n<p>\r\nKurumsal birleşme, maliyetleri azaltacak ve kaynak kullanımını optimize edecektir. Bürokratik süreçlerin sadeleşmesi, verimliliği artıracaktır.\r\n</p>\r\n</div>\r\n\r\n<!-- 11 -->\r\n<div class=\"section\">\r\n<h2>11. Uygulama Planı</h2>\r\n<p>\r\nReform süreci aşamalı şekilde yürütülmelidir. Mevzuat düzenlemeleri, kurumsal entegrasyon ve pilot uygulamalar sürecin temel adımlarıdır.\r\n</p>\r\n</div>\r\n\r\n<!-- 12 -->\r\n<div class=\"section\">\r\n<h2>12. Sonuç ve Değerlendirme</h2>\r\n<p>\r\nMevcut sistem sürdürülebilir değildir. Bu nedenle Gazi ve Şehit Yakınları Bakanlığı’nın kurulması bir tercih değil zorunluluktur.\r\n</p>\r\n<div class=\"highlight\">\r\nBu dönüşüm, devletin vatandaşına olan sorumluluğunun kurumsal ifadesidir.\r\n</div>\r\n</div>\r\n\r\n<div class=\"footer\">\r\nVatan Kahramanları Derneği © 2026\r\n</div>\r\n\r\n</div>"}]$vkd_page_updates_json$::jsonb;
BEGIN
  SELECT (layout_json::jsonb)->'hmExtraPages' INTO pages FROM hm_news_sites WHERE slug = 'vkd';
  IF pages IS NULL THEN
    RETURN; -- fresh DB: vkd sitesi yok
  END IF;

  FOR upd IN SELECT * FROM jsonb_to_recordset(updates) AS x(slug text, "bodyHtml" text)
  LOOP
    idx := NULL;
    FOR i IN 0..jsonb_array_length(pages) - 1 LOOP
      IF lower(trim(pages->i->>'slug')) = lower(trim(upd.slug)) THEN
        idx := i;
        EXIT;
      END IF;
    END LOOP;

    IF idx IS NULL THEN
      pages := pages || jsonb_build_array(
        jsonb_build_object(
          'id', 'vkd-page-' || replace(upd.slug, ' ', '-'),
          'title', initcap(replace(upd.slug, '-', ' ')),
          'slug', upd.slug,
          'bodyHtml', upd."bodyHtml",
          'enabled', true,
          'fullWidth', true
        )
      );
    ELSE
      pages := jsonb_set(
        jsonb_set(pages, ARRAY[idx::text, 'bodyHtml'], to_jsonb(upd."bodyHtml"), true),
        ARRAY[idx::text, 'enabled'],
        'true'::jsonb,
        true
      );
    END IF;
  END LOOP;

  UPDATE hm_news_sites
  SET
    layout_json = jsonb_set(layout_json::jsonb, '{hmExtraPages}', pages, true)::text,
    updated_at = now()
  WHERE slug = 'vkd';
END $$;
